import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useSocket } from '../../context/SocketContext';

export default function Navbar() {
  const { user, logout } = useAuth();
  const { notifications } = useSocket();
  const navigate = useNavigate();
  const [menuOpen, setMenuOpen] = useState(false);

  const unread = notifications.length;

  const initials = user?.name?.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);

  return (
    <nav className="navbar">
      <Link to="/" className="navbar-brand">
        ⚡ Skill<span>Bridge</span>
      </Link>

      <div className="navbar-links">
        <Link to="/search" className="btn btn-ghost btn-sm">Find Services</Link>

        {user ? (
          <>
            <Link to="/chat" className="btn btn-ghost btn-sm" style={{ position: 'relative' }}>
              💬 Chat
              {unread > 0 && (
                <span style={{
                  position: 'absolute', top: -4, right: -4,
                  background: 'var(--danger)', color: '#fff',
                  width: 18, height: 18, borderRadius: '50%',
                  fontSize: 10, display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontWeight: 700,
                }}>{unread}</span>
              )}
            </Link>

            <div style={{ position: 'relative' }}>
              <button
                onClick={() => setMenuOpen(!menuOpen)}
                style={{
                  background: 'var(--bg-elevated)', border: '1px solid var(--border)',
                  borderRadius: '50%', width: 38, height: 38, cursor: 'pointer',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  color: 'var(--accent)', fontWeight: 700, fontFamily: 'var(--font-display)',
                  fontSize: 13,
                }}
              >
                {user.avatar ? (
                  <img src={user.avatar} alt={user.name} style={{ width: 38, height: 38, borderRadius: '50%', objectFit: 'cover' }} />
                ) : initials}
              </button>

              {menuOpen && (
                <div style={{
                  position: 'absolute', right: 0, top: 48, width: 200,
                  background: 'var(--bg-card)', border: '1px solid var(--border)',
                  borderRadius: 'var(--radius)', overflow: 'hidden',
                  boxShadow: 'var(--shadow)', zIndex: 200,
                }}>
                  <div style={{ padding: '12px 16px', borderBottom: '1px solid var(--border)' }}>
                    <div style={{ fontWeight: 600, fontSize: 14 }}>{user.name}</div>
                    <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>{user.email}</div>
                    <span className={`badge badge-${user.role === 'admin' ? 'danger' : user.role === 'provider' ? 'success' : 'accent'}`}
                      style={{ marginTop: 6 }}>{user.role}</span>
                  </div>
                  {[
                    { label: '🏠 Dashboard', to: '/dashboard' },
                    user.role === 'user' && { label: '🔧 Become a Provider', to: '/provider-onboarding' },
                  ].filter(Boolean).map(item => (
                    <Link key={item.to} to={item.to}
                      onClick={() => setMenuOpen(false)}
                      style={{ display: 'block', padding: '10px 16px', fontSize: 14, color: 'var(--text-primary)', transition: 'background 0.15s' }}
                      onMouseEnter={e => e.target.style.background = 'var(--bg-elevated)'}
                      onMouseLeave={e => e.target.style.background = 'transparent'}
                    >{item.label}</Link>
                  ))}
                  <button onClick={() => { logout(); navigate('/'); setMenuOpen(false); }}
                    style={{ width: '100%', padding: '10px 16px', background: 'transparent', border: 'none', color: 'var(--danger)', cursor: 'pointer', textAlign: 'left', fontSize: 14 }}>
                    🚪 Logout
                  </button>
                </div>
              )}
            </div>
          </>
        ) : (
          <>
            <Link to="/login" className="btn btn-ghost btn-sm">Login</Link>
            <Link to="/register" className="btn btn-primary btn-sm">Sign Up</Link>
          </>
        )}
      </div>
    </nav>
  );
}
